mapper.select:
SELECT S.KEY , D.VALUE FROM IFA_CODE_LIST_DISP_PATTERN D INNER JOIN IFA_CODE_LIST_SELECT_PATTERN S ON D.CODE_LIST_ID = S.CODE_LIST_ID
AND D.DISP_PATTERN = #{dispPattern}
AND D.DISP_PATTERN = '1'
AND S.SELECT_PATTERN = #{selectPattern}
AND S.SELECT_PATTERN = '1'
AND D.KEY = S.KEY WHERE D.CODE_LIST_ID = #{codeListId} ORDER BY S.SELECT_ORDER

SELECT
    EXT_KEY
FROM
    IFA_CODE_LIST_EXT_SYSTEM E
WHERE
    E.CODE_LIST_ID = #{codeListId}
    AND E.API_TYPE = #{apiType}
    AND KEY = #{codeListKey}

SELECT
    KEY
FROM
    IFA_CODE_LIST_EXT_SYSTEM E
WHERE
    E.CODE_LIST_ID = #{codeListId}
    AND E.API_TYPE = #{apiType}
    AND EXT_KEY = #{codeListExtKey}

SELECT
    VALUE
FROM
    IFA_CODE_LIST_DISP_PATTERN D
WHERE
    D.CODE_LIST_ID = #{codeListId}

    AND D.DISP_PATTERN = #{dispPattern}


    AND D.DISP_PATTERN = '1'

    AND D.KEY = #{codeListKey}

SELECT
    KEY
FROM
    IFA_CODE_LIST_DISP_PATTERN D
WHERE
    D.CODE_LIST_ID = #{codeListId}

    AND D.DISP_PATTERN = #{dispPattern}


    AND D.DISP_PATTERN = '1'

    AND D.VALUE = #{codeListValue}
